query LolChampionCountersStatsOptionsQue.body:
query LolChampionCountersStatsOptionsQuery(
  $slug: String!
  $role: Rolename
  $patch: String
  $queue: VirtualQueue
  $counterVsChampionSlug: String
  $vsChampionRole: Rolename
  $rank: LolChampionRankFilter
  $region: Region
  $skip: Int!
  $top: Int = 10
  $sortField: LolChampionCountersSortField!
  $order: SortOrder!
) {
  lol {
    champion(
      filters: {
        slug: $slug
        role: $role
        patch: $patch
        queue: $queue
        rank: $rank
        region: $region
        gameMode: SUMMONER_RIFT
      }
    ) {
      cId: id
      activeFilters {
        ...LolChampionActiveFiltersFragment
      }
      countersOptions(
        top: $top
        skip: $skip
        sort: { field: $sortField, order: $order }
        filters: { vsChampionRole: $vsChampionRole, vsChampionSlug: $counterVsChampionSlug }
      ) {
        filterOptions {
          ...LolChampionCounterMatchupsFilterOptionsFragment
        }
        options {
          ...LolChampionCounterMatchupsFragment
        }
      }
    }
  }
}

